  const isbn = ol?.docs?.[0]?.isbn?.[0];
  if (isbn) cover = `https://covers.openlibrary.org/b/isbn/${isbn}-L.jpg`;
}
if (!cover) cover = 'https://covers.openlibrary.org/b/id/8739161-L.jpg';
