const requestor = $('📋 Book Request Form').item.json['Your Name'];
const bookWanted = $('📋 Book Request Form').item.json['Book Title You Want'];
const reason = $('📋 Book Request Form').item.json['Why do you want it? (optional)'] || 'No reason given';
const urgency = $('📋 Book Request Form').item.json['How urgent?'] || '🟢 Whenever free';

const found = $input.all();
let status = '❓ Not in library yet';
let foundTitle = bookWanted;

// Ensure the code uses 'Book Title' to match Airtable
if (found.length > 0 && found[0].json.fields) {
  const s = found[0].json.fields.Status || 'Unknown';

  // FIXED: Changed .Title to .['Book Title']
  foundTitle = found[0].json.fields['Book Title'] || bookWanted;

  if (s === 'Available') status = '✅ AVAILABLE NOW';
  else if (s === 'Issued') status = `📕 Currently lent out (due ${found[0].json.fields['Due Date'] || '?'})`;
  else status = `📌 ${s}`;
}

const msg = `📚 *Book Request — Bibliophile Concierge*\n\n👤 *From:* ${requestor}\n📖 *Book:* ${foundTitle}\n📊 *Status:* ${status}\n⚡ *Urgency:* ${urgency}\n💬 *Reason:* ${reason}\n\n🌷 _Respond on WhatsApp to confirm!_`;

return [{ json: { message: msg, requestor, bookWanted: foundTitle, status, urgency } }];

