// Change Mode to: "Run Once for All Items"
const responseText = $input.first().json.text;

// Clean up any extra text the AI might have added
const cleanText = responseText.replace(/```json/g, '').replace(/```/g, '').trim();

try {
    const events = JSON.parse(cleanText);
    // This part ensures Google Calendar gets a clean YYYY-MM-DD date
    return events.map(e => ({
        json: {
            ...e,
            eventDate: e.eventDate.includes('T') ? e.eventDate.split('T')[0] : e.eventDate
        }
    }));
} catch (err) {
    return [{ json: { title: "Global Literary Update", description: "Check news for May 2026", eventDate: "2026-05-19" } }];
}

const rawText = $node["Basic LLM Chain1"].json.text;

// Extracting the JSON array from the LLM text
const start = rawText.indexOf('[');
const end = rawText.lastIndexOf(']') + 1;

if (start === -1 || end === 0) {
  return [{ json: { myHtml: "<p>No data found in AI response.</p>" } }];
}

let jsonString = rawText.substring(start, end).replace(/\n/g, ' ').trim();

try {
  const bookList = JSON.parse(jsonString);
  let combinedHtml = "";

  // Building the one large HTML block
  bookList.forEach(book => {
    combinedHtml += `
      <div style="background: rgba(255, 255, 255, 0.07); margin: 20px 0; padding: 20px; border-left: 5px solid #d4af37; border-radius: 8px;">
        <h3 style="margin-top: 0; color: #ffd700;">✨ ${book.title || 'Untitled'}</h3>
        <p style="line-height: 1.6; color: #f4e4bc;">${book.description || 'No description available.'}</p>
        <a href="${book.link || '#'}" style="color: #d4af37; font-weight: bold; text-decoration: none;">Read the full tale →</a>
      </div>`;
  });

  // This returns EXACTLY ONE item to Gmail
  return [{ json: { myHtml: combinedHtml } }];

} catch (e) {
  return [{ json: { myHtml: "<p>Error parsing news data.</p>" } }];
}

